    #[test]
    fn loads_legacy_session_json_object_without_archived_at() {
        // given a legacy single-object session_json from before archived_at existed
        let path = temp_session_path("legacy-no-archived");
        let legacy = JsonValue::Object(
            [
                ("version".to_string(), JsonValue::Number(1)),
                (
                    "messages".to_string(),
                    JsonValue::Array(vec![ConversationMessage::user_text("hi").to_json()]),
                ),
            ]
            .into_iter()
            .collect(),
        );
        fs::write(&path, legacy.render()).expect("legacy file should write");

        // when
        let restored = Session::load_from_path(&path).expect("legacy session should load");
        fs::remove_file(&path).expect("temp file should be removable");

        // then
        assert_eq!(restored.archived_at, None);
    }

    #[test]
    fn persists_and_restores_archived_at_via_jsonl() {
        // given a session marked archived
        let mut session = Session::new();
        session.archived_at = Some("2026-04-07T12:00:00Z".to_string());
        session
            .push_user_text("after archive")
            .expect("user message should append");

        // when round-tripped through JSONL persistence
        let path = temp_session_path("archived-jsonl");
        session.save_to_path(&path).expect("session should save");
        let restored = Session::load_from_path(&path).expect("session should load");
        fs::remove_file(&path).expect("temp file should be removable");

        // then archived_at survives both write and read
        assert_eq!(
            restored.archived_at.as_deref(),
            Some("2026-04-07T12:00:00Z")
        );
        assert_eq!(restored, session);
    }

    #[test]
    fn persists_and_restores_archived_at_via_json_object() {
        // given a session marked archived, serialized via to_json/from_json
        let mut session = Session::new();
        session.archived_at = Some("2026-04-07T13:30:00Z".to_string());

        // when
        let value = session.to_json().expect("session should serialize");
        let restored = Session::from_json(&value).expect("session should deserialize");

        // then
        assert_eq!(
            restored.archived_at.as_deref(),
            Some("2026-04-07T13:30:00Z")
        );
    }

    #[test]
    fn fork_clears_archived_at() {
        // given an archived session
        let mut session = Session::new();
        session.archived_at = Some("2026-04-07T14:00:00Z".to_string());

        // when forked
        let forked = session.fork(None);

        // then the fork starts unarchived
        assert_eq!(forked.archived_at, None);
    }

